import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"PagedAttention 原理详解","description":"介绍 PagedAttention 如何借鉴虚拟内存分页思想高效管理 KV Cache，消除内存碎片与浪费。","frontmatter":{"title":"PagedAttention 原理详解","description":"介绍 PagedAttention 如何借鉴虚拟内存分页思想高效管理 KV Cache，消除内存碎片与浪费。"},"headers":[],"relativePath":"inference/vllm/paged-attention.md","filePath":"inference/vllm/paged-attention.md","lastUpdated":1782803909000}`),a={name:`inference/vllm/paged-attention.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="pagedattention-原理详解" tabindex="-1">PagedAttention 原理详解 <a class="header-anchor" href="#pagedattention-原理详解" aria-label="Permalink to “PagedAttention 原理详解”">​</a></h1><p>大语言模型推理服务的性能瓶颈往往在于<strong>内存</strong>。在自回归解码过程中，每个输入 Token 都会生成注意力机制中的 Key 与 Value 张量，这些张量被缓存在 GPU 内存中以生成后续 Token，统称为 <strong>KV Cache</strong>。PagedAttention 借鉴操作系统虚拟内存分页思想，高效管理 KV Cache，显著减少内存浪费。</p><h2 id="_1-kv-cache-的挑战" tabindex="-1">1. KV Cache 的挑战 <a class="header-anchor" href="#_1-kv-cache-的挑战" aria-label="Permalink to “1. KV Cache 的挑战”">​</a></h2><p>KV Cache 具备以下特点：</p><ul><li><strong>体积庞大</strong>：以 LLaMA-13B 为例，单个序列的 KV Cache 可占用高达 1.7 GB GPU 内存。</li><li><strong>动态变化</strong>：其大小取决于序列长度，而序列长度具有高度可变性与不可预测性。</li></ul><p>传统系统由于内存碎片与过度预留，导致 <strong>60%–80%</strong> 的内存浪费。</p><h2 id="_2-pagedattention-的引入" tabindex="-1">2. PagedAttention 的引入 <a class="header-anchor" href="#_2-pagedattention-的引入" aria-label="Permalink to “2. PagedAttention 的引入”">​</a></h2><p>在论文 <em>Efficient Memory Management for Large Language Model Serving with PagedAttention</em> 中，作者提出了 PagedAttention，一种受虚拟内存分页启发的算法。</p><p>操作系统通过分页管理物理内存页帧（Page Frame），在内存不足时换出暂不使用的页面。PagedAttention 将这一思想应用于 LLM 推理：</p><ul><li>将连续的逻辑 KV 块映射到非连续的物理内存块。</li><li>每个块包含固定数量 Token 的 Key 与 Value。</li><li>通过块表（Block Table）维护逻辑块到物理块的映射。</li></ul><img src="https://blog.vllm.ai/assets/figures/annimation0.gif" alt="PagedAttention 将 KV Cache 划分为多个块" style="zoom:50%;"><blockquote><p>图示：PagedAttention 将 KV Cache 划分为多个块，块在物理内存中不要求连续。</p></blockquote><p>通过类比：</p><ul><li>块 ↔ 页面（page）</li><li>Token ↔ 字节（byte）</li><li>序列 ↔ 进程（process）</li></ul><p>序列的连续逻辑块通过 Block Table 映射到物理内存中的非连续块，并随新 Token 生成按需分配。</p><h2 id="_3-内存浪费的消除" tabindex="-1">3. 内存浪费的消除 <a class="header-anchor" href="#_3-内存浪费的消除" aria-label="Permalink to “3. 内存浪费的消除”">​</a></h2><p>传统系统将 KV Cache 保存在连续内存空间中，为每个请求预分配固定完整区域。由于输入输出长度差异大，导致三类浪费：</p><ul><li><strong>内部碎片（Internal Fragmentation）</strong>：预分配较大区域，最终未完全使用。</li><li><strong>保留浪费（Reservation）</strong>：为整个序列持续预留内存，即使部分未使用也无法共享。</li><li><strong>外部碎片（External Fragmentation）</strong>：块大小与请求长度不匹配，产生无法复用的“空隙”。</li></ul><p>PagedAttention 允许将连续的 Key 与 Value 张量存储在<strong>非连续内存空间</strong>中，通过动态分配内存块：</p><ul><li>消除外部碎片。</li><li>最大程度减少内部碎片：内存浪费只发生在序列的最后一个块。</li></ul><p>据论文所述，传统实现中仅 20%–40% 的 KV Cache 被有效使用，而 vLLM 的 PagedAttention 将效率提升至接近 96%。</p><h2 id="_4-高效的内存共享" tabindex="-1">4. 高效的内存共享 <a class="header-anchor" href="#_4-高效的内存共享" aria-label="Permalink to “4. 高效的内存共享”">​</a></h2><p>PagedAttention 通过 Block Table 天然支持内存共享，类似于操作系统多个进程共享物理页面：</p><ul><li>追踪每个物理块的<strong>引用计数</strong>。</li><li>实施<strong>写时复制（Copy-on-Write）</strong>，在需要修改共享内容时自动创建副本。</li></ul><p>以下解码策略均可受益：</p><h3 id="_4-1-并行采样-parallel-sampling" tabindex="-1">4.1 并行采样（Parallel Sampling） <a class="header-anchor" href="#_4-1-并行采样-parallel-sampling" aria-label="Permalink to “4.1 并行采样（Parallel Sampling）”">​</a></h3><p>从同一输入生成多个输出样本时，vLLM 可共享输入 Prompt 阶段的计算与内存。</p><img src="https://blog.vllm.ai/assets/figures/annimation2.gif" alt="并行采样中共享 KV Cache"><h3 id="_4-2-束搜索-beam-search" tabindex="-1">4.2 束搜索（Beam Search） <a class="header-anchor" href="#_4-2-束搜索-beam-search" aria-label="Permalink to “4.2 束搜索（Beam Search）”">​</a></h3><p>每步保留最可能的候选路径，vLLM 可在不同 Beam 分支间高效复用共享前缀。</p><h3 id="_4-3-共享前缀-shared-prefix" tabindex="-1">4.3 共享前缀（Shared Prefix） <a class="header-anchor" href="#_4-3-共享前缀-shared-prefix" aria-label="Permalink to “4.3 共享前缀（Shared Prefix）”">​</a></h3><p>多个请求使用相同 System Prompt 时，vLLM 会预存并共享该前缀的 KV Cache。</p><h3 id="_4-4-混合解码策略" tabindex="-1">4.4 混合解码策略 <a class="header-anchor" href="#_4-4-混合解码策略" aria-label="Permalink to “4.4 混合解码策略”">​</a></h3><p>贪婪解码、Top-K 采样与束搜索等可并发使用，vLLM 灵活管理不同策略下的缓存共享。</p><h2 id="_5-性能收益" tabindex="-1">5. 性能收益 <a class="header-anchor" href="#_5-性能收益" aria-label="Permalink to “5. 性能收益”">​</a></h2><p>PagedAttention 的内存共享机制大幅减少了复杂采样算法的内存开销。据测试结果：</p><ul><li>并行采样与束搜索等方法内存使用最多可减少 <strong>55%</strong>。</li><li>吞吐量提升高达 <strong>2.2 倍</strong>。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>PagedAttention 是 vLLM 的核心技术，通过借鉴操作系统分页机制，将 KV Cache 管理从连续预分配转变为动态块分配，显著提升了内存利用率与推理吞吐量。它支持多种模型与解码策略，是高效 LLM 服务的关键基石。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ul><li><a href="https://blog.vllm.ai/2023/06/20/vllm.html" target="_blank" rel="noreferrer">vLLM Blog: PagedAttention</a></li><li><a href="https://arxiv.org/abs/2309.06180" target="_blank" rel="noreferrer">PagedAttention Paper</a></li></ul>`,41)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};